var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결론부터 말하면…… 성배란, 살아있는 인간입니다.","JPN":"結論から言いますと……聖杯とは、生きている人間です。","ENG":"In a nutshell... the Holy Grail is a living human.","TWN":"從結論說起……聖杯，就是活生生的人。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"적어도 학회는 그렇게 생각하고 있어요.","JPN":"少なくとも学会ではそう捉えています。","ENG":"At least that is what the Society thinks.","TWN":"至少學會是這麼認為的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"성배가 인간이라고?","JPN":"聖杯が人間？","ENG":"The Holy Grail is a person?","TWN":"聖杯是人？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"갑자기 무슨 뚱딴지 같은 소리야, 종이 수녀?","JPN":"ペーパーシスター、何とぼけたこと言ってんだ？","ENG":"What kind of nonsense is that, paper nun?","TWN":"你突然在說什麼傻話，紙修女？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지난 성무에서 심의회는 관리거부 구역의 어떤 이교도 마을을 조사했던 적이 있습니다.","JPN":"前回の聖務で、審議会は管理拒否区域のある異教徒の村を調査しました。","ENG":"During the last sacred mission, the Miracle Investigation Council investigated a pagan village in the Anti-Administration Zone.","TWN":"在上次的聖務，議會曾經調查過拒絕管理區域的某個異教徒村落。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그곳에서 집단 광증 및 소요 사태가 발생하고 있다는 제보를 받았기 때문이었죠.","JPN":"そこで集団狂症や騒動が発生しているという報告があったのです。","ENG":"There were reports of mass mania and civil unrest occurring over there.","TWN":"因為接到舉報說，那裡發生集體癲狂騷動事件。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결과적으로 그곳은 당시 학회장, 안나 맥크레디가 의식을 위해 준비한 공간이었어요.","JPN":"調べたところ、そこは当時の学会長、アンナ・マクレディーが儀式のために設けた場所ということがわかりました。","ENG":"In the end, it was found out that the place was used by the then-President, Anna MacCready, for her ritual.","TWN":"結果，那裡是當時的學會長，安娜·麥克蕾蒂為儀式準備的空間。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 자네가 안나 맥크레디라는 이름에 반응했던 거로군.","JPN":"君がアンナ・マクレディーという名前に反応したのはそのせいか。","ENG":"So that's why you reacted to the name, Anna MacCready.","TWN":"所以你才會對安娜·麥克蕾蒂這個名字有反應。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네, 부끄럽지만 그 이름을 듣고서야 비로소 깨달을 수 있었습니다.","JPN":"はい、お恥ずかしいですがその名前を聞いてやっと気がつきました。","ENG":"Yes. I am embarrassed to admit that I only realized after hearing that name.","TWN":"是的，我很慚愧，因為聽到這個名字後我才意識到。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"조사 결과, 안나 맥크레디는 오래전부터 자신의 영생을 위해 의식을 옮길 그릇을 선별해 두었어요.","JPN":"調査の結果、アンナ・マクレディーは以前より不老不死を得るために、自分の魂を移す器を選別しておきました。","ENG":"According to the investigation's findings, Anna MacCready has long sought a vessel to transfer her consciousness for eternal life.","TWN":"調查結果顯示，安娜·麥克蕾蒂從很久以前開始就為自己的永生挑選了轉移意識的器皿。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 그 이교도 마을 말고도 그릇을 선별하는 시설은 더 있었다는 뜻이죠.","JPN":"つまり、器を選び出すための施設はあの異教徒の村だけではなかったということです。","ENG":"In other words, there were more facilities besides that pagan village that were used for choosing the right vessel.","TWN":"也就是說，除了異教徒村落之外，還有篩選器皿的設施。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"실제로 전 그곳에서 구출한 사교도 아이가 <color=#ffd34c>무언가</color>에 깃들어 있는 것을 목격하였습니다.","JPN":"実際、私はそこから救出した邪教徒の子どもに<color=#ffd34c>何か</color>が取り憑いているところを目撃しました。","ENG":"I have also witnessed the pagan child whom we rescued being possessed by <color=#ffd34c>something</color> myself.","TWN":"事實上，我親眼目睹了從那裡救出的異教徒孩童身體裡寄宿著<color=#ffd34c>某種東西</color>的事實。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILDREN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 아이를 읽어내기 위해 직접 심문을 진행하기도 했지만, 그 결과는…….","JPN":"その子どもの潜在意識を読み取るために尋問を行いましたが……","ENG":"I interrogated her myself to read her, but the results of that were...","TWN":"為了從那個孩子身上獲取情報，我親自進行了審問，但結果……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILDREN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어, 어떻게 됐는데?","JPN":"ど、どうなったんだ？","ENG":"H-how did it go?","TWN":"怎，怎麼樣了？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILDREN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"많은 일이 있었습니다.","JPN":"お話するには長くなります。","ENG":"A lot had happened.","TWN":"發生了很多事情。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어, 그렇구나. 미안.","JPN":"あ……そうか。悪い。","ENG":"Oh, I see. Sorry for asking.","TWN":"呃，原來如此，對不起。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"흠, 아무튼…….","JPN":"ごほん……とにかく。","ENG":"Hmm... anyway...","TWN":"嗯，總之……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"신은 자신을 본떠 흙으로 몸을 빚고, 숨을 불어넣어 인간을 창조했다는 해석이 있죠.","JPN":"神は自分を模った体を土で作り、そこに息を吹き込み人間を創造したのだと言われます。","ENG":"There is an interpretation that god made mankind in his own image, made them from dust, and breathed life into them.","TWN":"有解析認為，神以自己為參照，用泥土捏造身體，注入呼吸，並創造了人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 여기서 인간의 육체를 하나의 <color=#ffd34c>그릇</color>으로 빗댄다면…….","JPN":"よって、人間の肉体を一つの<color=#ffd34c>器</color>だとすると……","ENG":"Thus, if we compare a human body to a <color=#ffd34c>vessel</color> here...","TWN":"也就是說，如果把人類的肉體比喻成一個<color=#ffd34c>器皿</color>……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성배란, 신의 피를 담는 그릇.","JPN":"聖杯は、神の血を宿す器。","ENG":"The Holy Grail is a vessel that can contain the blood of god.","TWN":"聖杯，就是盛裝神血的器皿。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다시말해, 신적 존재를 육신에 품고서도 버틸 수 있는 <color=#ffd34c>특이체질</color>의 인간입니다.","JPN":"つまり、神的な存在をその身に宿しても耐えられる、<color=#ffd34c>特異体質</color>の人間です。","ENG":"In other words, it is referring to a human with an <color=#ffd34c>idiosyncratic body type</color> that can embrace a divine being.","TWN":"換句話說，就是肉體能夠承受神之存在的<color=#ffd34c>特殊體質</color>的人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"특이체질의 인간이라.","JPN":"特異体質の人間か。","ENG":"A human with an idiosyncratic body type.","TWN":"特殊體質的人類。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그릇이란, 결국 리오나 하트와 비슷한 케이스로군.","JPN":"器とは……リオナ・ハートのようなケースだな。","ENG":"So a vessel is something similar to the case of Liona Hartt.","TWN":"所謂器皿，歸根結底是和萊歐娜·哈特類似的例子。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 제임스가 성배를 찾고자 하는 이유는 뻔하겠지.","JPN":"だとすると、ジェームスが聖杯を探す理由は火を見るよりも明らかだ。","ENG":"Then it's obvious why James is searching for the Holy Grail.","TWN":"那麼詹姆斯想要尋找聖杯的理由就顯而易見了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"역시 눈치가 빠르시군요. 모건.","JPN":"さすが理解が早いですね、モーガン。","ENG":"As always, you catch on fast, Morgan.","TWN":"洞察力果然敏銳，摩根。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그자는 지금 현실로 불러내서는 안 될 것을, 성배를 통하여 불러내려는 겁니다.","JPN":"彼は現実に呼び出してはいけない存在を、聖杯を通して呼び出そうとしているのです。","ENG":"He is trying to summon what should not be summoned to the Normalside through the Holy Grail.","TWN":"他是想透過聖杯，來召喚不能在現實中召喚出來的東西。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 더럽게 복잡하네.","JPN":"ったく、ややこしいな。","ENG":"Sheesh, that's bloody complicated.","TWN":"真是的，好複雜啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"난 머리가 나빠서 이런 건, 한 번에 감이 안 온다고.","JPN":"俺は頭が悪いからこういうのっていまいちピンとこないんだよ。","ENG":"Look, I'm not that bright, so this takes me a while to get my head around.","TWN":"我腦袋不好，你們這麼說讓我很摸不著頭緒欸？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 그럼 자네를 위해 잠시 정리하는 시간을 가져볼까.","JPN":"はは、では君のためにもう一度情報をまとめてみようか。","ENG":"Hah hah, then how about a refresher to help you understand?","TWN":"哈哈，那就讓我為你梳理一下吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"17년 전, 형님과 요한 추기경께서는 성황청의 파편을 두고 제임스와 겨루었지.","JPN":"17年前、兄貴とヨハン枢機卿は聖皇庁の破片を巡ってジェームスと競り合っていた。","ENG":"17 years ago, your grandfather and Cardinal Johan fought James over the Fragment at the Holy Curia.","TWN":"17年前，大哥和約翰樞機主教就聖皇廳的碎片與詹姆斯展開了較量。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 결과, 파편은 행방불명되었고, 두 분은 비밀리에 탐색을 이어갔다네.","JPN":"だが破片は行方不明となり、その後二人は秘密裏に捜索を続けた。","ENG":"As a result, the Fragment went missing, but the two kept searching for it in secret.","TWN":"結果，碎片下落不明，二個人暗中繼續搜尋。"},"stage":{"bg":"CHURCH","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"차원함선을 수배하신 걸 보면, 그 파편은 이면세계 어딘가에 있는 게 확실해.","JPN":"次元艦船を手配していたことから、その破片は裏世界のどこかにあると推測できる。","ENG":"Seeing how they borrowed dimensional ships, I'm certain the Fragment is in the Counterside.","TWN":"從次元戰艦的租賃情況看，那碎片肯定在異界的某個地方。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아아, 그래서 고고학부장이 엘리시움의 악기로 차원 균열을 만든다, 어쩐다 한거구나!","JPN":"あー、考古学部長がエリシウムの楽器で次元の亀裂を作るだのなんだの言ってたのはそのせいなんだ！","ENG":"Oh...! So that's what the Dean of Archeology meant by creating a dimensional rift using Elysium's instrument!","TWN":"啊，所以考古學教授才說要用愛樂組織的樂器製造次元裂縫！"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야? 교수가 차원 균열을 만든다고? 처음 듣는데?","JPN":"なに？　教授が次元の亀裂を作る？　それは初耳だぞ。","ENG":"What? The Professor's going to create a dimensional rift? That's the first I'm hearing about it.","TWN":"什麼？教授要製造次元裂縫？我第一次聽說啊？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"앗! 이건 비밀이었는데! 실수~♬","JPN":"あっ、これ内緒だった！　えへっ♬","ENG":"Oh! That was supposed to be a secret! Oops!♬","TWN":"哎呀！這是個秘密呢！一不小心說溜嘴了～♬"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"안나 맥크레디는 영생을 위해, 평생을 바친 인물입니다.","JPN":"アンナ・マクレディーは不老不死を手に入れるために生涯を捧げた人物です。","ENG":"Anna MacCready is someone who devoted her entire life for immortality.","TWN":"安娜·麥克蕾蒂這個人為了永生，奉獻了畢生。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"영원한 생명을 통해서 언젠가 호수의 위치를 알아낼 수 있다고 생각했겠죠.","JPN":"不老不死になれば、いつか湖の場所もわかると思ったのでしょう。","ENG":"She must have believed that she would be able to locate the Lake someday through immortal life.","TWN":"也許她認為，透過永遠的生命，總有一天會找到湖水的位置。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 교수가 말한 성황청의 파편이란 성배실험의 그릇, 그 피험체를 뜻할 겁니다.","JPN":"つまり、教授の言っていた聖皇庁の破片とやらは聖杯実験の器、被検体のことだと思います。","ENG":"So, the Holy Curia's Fragment the Professor mentioned is referring to a test subject. The vessel for the Holy Grail experiment.","TWN":"也就是說，教授所說的聖皇廳的碎片表示聖杯實驗的器皿，就是那個受試者。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 그렇다는 건…….","JPN":"待てよ。ってことは……","ENG":"Wait, then that means...","TWN":"等等，那就是說……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"십수 년 전에 사라진 인간이 지금껏 이면세계를 표류하고 있다는 뜻이잖아?","JPN":"十数年前に消えた人間が、今も裏世界を漂流してるってことじゃないか？","ENG":"someone who disappeared decades ago has been drifting in the Counterside all this time.","TWN":"十幾年前消失的人，至今還在異界漂流？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"찾을 수 있긴 한 거야? 침식체가 되어버렸으면 어떡해?","JPN":"それって見つかるもんなのか？　侵食体になっていたらどうする？","ENG":"Then, can we even find this person? What if this person's already turned into a C.O.?","TWN":"能找到嗎？如果變成侵蝕體了怎麼辦？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이면세계에서 확신할 수 있는 것은 아무것도 없습니다.","JPN":"裏世界において確信が持てるものは何もありません。","ENG":"There is nothing we can guarantee in the Counterside.","TWN":"在異界中，沒有什麼是可以確定的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"때때로 고심도의 이면세계는 현실과 시간의 흐름이 다르다고 하니까요.","JPN":"高深度の裏世界では、現実と時間の流れが違うとも言いますしね。","ENG":"It is said that sometimes, time in the hyperdepths of the Counterside and the Normalside tends to flow differently.","TWN":"有時，高深度異界和現實中的時間推移是不同的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아마도 형님께서는 그날의 실패에 대한 책임을 지려고 하셨던 것 같아.","JPN":"おそらく、兄貴はあの失敗の責任を取ろうとしていたのだと思う。","ENG":"I believe Sir Burnett was trying to take responsibility for the failure of that day.","TWN":"也許大哥是想對那天的失敗負責吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 방식대로…… 성배를 제거하여, 미래의 후환을 없애기 위해서겠지.","JPN":"機関のやり方で……聖杯を排除し、災いの種を取り除くためだったのだろう。","ENG":"He must have wished to allay concerns about the future... by using the Institution's approach to destroy the Holy Grail.","TWN":"按照機關的方式……銷毀聖杯，除去未來的後患。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"함선 없이 맨몸으로 차원 균열에 다이브하는 건 자살행위에 가까워.","JPN":"艦船もなく身一つで次元の亀裂にダイブするのは自殺行為同然だ。","ENG":"Diving into a dimensional rift without a ship is basically committing suicide.","TWN":"在沒有艦船的情況下，毫無防護跳入次元裂縫中，無疑是自殺行為。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"최대한 성공률을 높이기 위해서는, 이전에 균열이 발생했던 곳을 노릴 수밖에 없지.","JPN":"成功率を最大限に引き上げるためには、以前に亀裂が生じた場所を狙うのが得策。","ENG":"In order to increase one's chances of success as much as possible, one must aim to dive in a place where a rift has already been opened before.","TWN":"而為了最大限度提高成功率，就只能瞄準之前出現裂縫的地方。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좌표를 몰라도, 한 번 균열이 발생했던 곳과 같은 세계로 연결될 가능성이 크니까.","JPN":"座標がわからずとも、一度亀裂が発生した場所と同じ世界に繋がる可能性は高いからな。","ENG":"Because even if you don't know the coordinates, a place where a rift occurred is likely to be connected to the same world.","TWN":"即使不知道座標，也很有可能連接到與出現過的裂縫通向的同一世界中。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아마 제임스는 17년 전, 피험체가 차원 균열에 휘말린 곳을 알고 있을 거야.","JPN":"ジェームスは17年前に被検体が次元の亀裂に巻き込まれた場所を知っているはずだ。","ENG":"And James seems to know where the test subject was caught up in a dimensional rift 17 years ago.","TWN":"也許詹姆斯知道，17年前受試者被捲入的次元裂縫在哪裡。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제임스를 잡기 위해서는 우리가 한발 먼저 거기에 도착해서 그를 습격해야만 해.","JPN":"あの男を捕まえるには、俺たちがその場所へ先回りし奇襲をかける必要がある。","ENG":"To catch James, we need to get there before he does and ambush him.","TWN":"想抓住詹姆斯，我們就必須先一步到達那裡，然後偷襲他。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 거기가 어딘데?","JPN":"で、その場所はどこなんだ？","ENG":"And where's that exactly?","TWN":"呃？所以那裡是哪裡？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……크흠.","JPN":"……ゴホン。","ENG":"...Ahem.","TWN":"……咳咳。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어쩔 수 없군. 학회 측과 공조하는 건 내키지 않지만.","JPN":"仕方ないな。学会との協力は気乗りしないが……","ENG":"I don't like cooperating with the Society, but I suppose we have no other choice.","TWN":"沒辦法了，雖然我很不樂意跟學會合作。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"리벳이라고 했나? 이번만큼은 서로 목적이 부합하는 것 같은데…….","JPN":"リベットと言ったか。今回はお互いの目的が一致していると思うが……","ENG":"Rivet, right? It seems like our objectives seem to be in line...","TWN":"你叫里維對吧？這次，我們的目的好像一致……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤가? 우리와 손을 잡지 않겠나?","JPN":"どうだ、俺たちと手を組まないか？","ENG":"What do you say? Fancy a team-up?","TWN":"怎麼樣？要不要和我們聯手？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"흥이거든? 나한테 뭐가 떨어지는 것도 아닌데 왜 프리드웬이랑 손을 잡아?","JPN":"ふーんだ。アタシにはなんのメリットもないのに、プリドウェンと協力するわけないでしょ。","ENG":"As if! Why would I join forces with Prydwen when I get nothing in return?","TWN":"哼？我又得不到什麼，那我憑什麼跟普利多溫聯手？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 그건 그렇지.","JPN":"はは、確かにそうだな。","ENG":"Hah hah, that is true...","TWN":"哈哈，那倒是。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 이건 어떤가? 모든 일이 끝나면 제임스의 신병은 자네에게 넘기도록 하지.","JPN":"ではこれはどうだ？　すべてが終わったら、ジェームスの身柄は君に渡す。","ENG":"Then how about this? Once everything is settled, I'll hand over James to you.","TWN":"那這個怎麼樣？等一切結束之後，詹姆斯就交給你了。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그자를 죽이든, 살리든 자네 마음대로 해.","JPN":"生かすも殺すも君の好きにすればいい。","ENG":"Whether you kill him or keep him alive, that's up to you.","TWN":"你要殺他，還是留活口，隨你便。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"호오오……!?","JPN":"へえ……？","ENG":"Ooh...!","TWN":"喔……？！"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 할배! 지금 얘를 믿자는 거야?","JPN":"待てよ、ジジイ！　こいつのこと信用しようって言うのか？","ENG":"Wait, old chap! You're really going to trust her?!","TWN":"等一下，老頭！你憑什麼相信她？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"안나 맥크레디는 죽었어. 그릇을 선별했던 시설도 지금은 당연히 존재하지 않겠지.","JPN":"アンナ・マクレディーは死んだ。当然、器を選別していた施設も今は存在してないだろう。","ENG":"Anna MacCready's dead. And even her facilities for selecting vessels don't exist anymore.","TWN":"安娜·麥克蕾蒂早就死了。篩選器皿的設施現在當然也不存在。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 그 위치에 대한 정보를 알아내기 위해서는 학회측 정보원이 필요해.","JPN":"だからその場所を特定できる情報を手に入れるためには、学会側の協力者が必要だ。","ENG":"So, if we want intel about that location, we need an informant from the Society.","TWN":"所以為了掌握那個位置的情報，需要學會方的情報員。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 괜찮겠어?","JPN":"でもいいのかよ？","ENG":"Are you sure about this?","TWN":"真的沒關係嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배는 그 교수한테 한 방 먹여주고 싶은 거 아니었냐고?","JPN":"ジジイはあの教授に一発食らわせたかったんじゃないのか？","ENG":"Weren't you just in it to give that Professor a punch in the face?","TWN":"老頭你難道不是想給那個教授一拳嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"좋아! 그 대신 배신하기 없기다?","JPN":"いいよ！　その代わり、裏切ったら容赦しないからね。","ENG":"Okay! But no backstabbing, okay?","TWN":"好吧！但可不能背叛我啊？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"배신하면, 과녁판 대신 쇠꼬챙이 잔뜩 박아줄 거야?","JPN":"金属ドリルで穴ぼこにしちゃうよ。","ENG":"If you betray me, I'm gonna put skewers in your body until there's no more room!","TWN":"要是敢背叛我，我就把鐵釘釘滿你身上！"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 걱정말게.","JPN":"はは、心配するな。","ENG":"Hah hah, don't worry.","TWN":"哈哈，別擔心。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"신사는 거짓말을 하지 않거든.","JPN":"紳士は嘘をつかないものなんでね。","ENG":"A gentleman never lies.","TWN":"紳士是不會說謊的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};